<?php
namespace Tests\Unit\Domain\Combat;use App\Domain\Combat\CombatActionResolver;use App\Domain\Combat\CombatActionType;use App\Domain\Combat\CombatResultStatus;use App\Domain\Combat\CombatStateStatus;use App\Domain\Combat\Data\CombatCommand;use App\Domain\Combat\Data\CombatState;use App\Domain\Combat\Data\CombatantStats;use App\Domain\Random\RandomNumberGenerator;use PHPUnit\Framework\TestCase;class ResolverRandom implements RandomNumberGenerator{public $v;public function __construct($v){$this->v=$v;}public function randomInt(int $a,int $b):int{return array_shift($this->v);}}class CombatActionResolverTest extends TestCase{private function f($id,$h=20,$a=5){return new CombatantStats($id,$id,$h,$h,$a,0,5,0,0,1.5,1,0);}private function state(){return new CombatState($this->f('c'),$this->f('m'),20,20,1,'c','c',CombatStateStatus::IN_PROGRESS);}public function test_one_action_and_round_transition(){$r=new CombatActionResolver(new ResolverRandom([1,10000,1,10000]));$a=$r->resolve($this->state(),new CombatCommand(null,'c',CombatActionType::BASIC_ATTACK,'m'));$this->assertSame(1,$a->resolvedAction()->roundNumber());$this->assertSame('m',$a->nextState()->nextActorIdentifier());$b=$r->resolve($a->nextState(),new CombatCommand(null,'m',CombatActionType::BASIC_ATTACK,'c'));$this->assertSame(1,$b->resolvedAction()->roundNumber());$this->assertSame(2,$b->nextState()->roundNumber());$this->assertSame(20,$a->previousState()->monsterCurrentHealth());}public function test_invalid_commands_are_rejected(){$r=new CombatActionResolver(new ResolverRandom([]));foreach([new CombatCommand(null,'m',CombatActionType::BASIC_ATTACK,'c'),new CombatCommand(null,'c',CombatActionType::BASIC_ATTACK,'c')] as $command){try{$r->resolve($this->state(),$command);$this->fail();}catch(\InvalidArgumentException $e){$this->assertTrue(true);}}}public function test_kill_is_terminal(){$state=new CombatState($this->f('c',20,50),$this->f('m',5,1),20,5,1,'c','c',CombatStateStatus::IN_PROGRESS);$s=(new CombatActionResolver(new ResolverRandom([1,10000])))->resolve($state,new CombatCommand(null,'c',CombatActionType::BASIC_ATTACK,'m'));$this->assertSame(CombatResultStatus::CHARACTER_VICTORY,$s->nextState()->status());$this->assertNull($s->nextState()->nextActorIdentifier());}}
